// schedulingEngine.js

const cron = require('node-cron');
const mongoose = require('mongoose');
const { NotificationLog } = require('./models/NotificationLog'); // Import model for logging notifications
const { Task } = require('./models/Task'); // Import Task model
const telegramBot = require('./telegramBot'); // Import telegram bot instance

/**
 * Scheduling Engine to manage recurring tasks and sending notifications.
 * @module SchedulingEngine
 */

/**
 * Start the scheduling engine.
 */
function startSchedulingEngine() {
  // Schedule a job to run every minute
  cron.schedule('* * * * *', async () => {
    console.log('Scheduling Engine running...');

    const tasks = await Task.find({ status: 'active' }); // Get all active tasks

    tasks.forEach(async (task) => {
      // Check if the task needs to trigger a notification
      const currentDate = new Date();
      const currentDay = currentDate.getUTCDay(); // Get current day (0=Sun, 1=Mon, ...)
      const currentTime = currentDate.toUTCString().split(' ')[4]; // Get current time in HH:MM:SS format

      // Check recurrence logic
      const { recurrence } = task;
      if (recurrence.type === 'daily' && currentTime === recurrence.time) {
        await sendNotification(task);
      } else if (recurrence.type === 'weekly' && recurrence.daysOfWeek.includes(currentDay) && currentTime === recurrence.time) {
        await sendNotification(task);
      }
      // TODO: Implement logic for custom recurrence if required
    });
  });
}

/**
 * Send notification to group for a given task.
 * @param {Object} task - Task object containing task details.
 * @returns {Promise<void>}
 */
async function sendNotification(task) {
  try {
    const message = `Task Reminder: ${task.title} for the group ${task.groupId}`;
    await telegramBot.sendMessage(task.groupId, message); // Send message via Telegram

    // Log notification
    const log = new NotificationLog({
      taskId: task.id,
      sentAt: new Date(),
      status: 'success',
      retryCount: 0,
    });
    await log.save(); // Save notification log
  } catch (error) {
    console.error('Failed to send notification:', error);
    // Log failure
    const log = new NotificationLog({
      taskId: task.id,
      sentAt: new Date(),
      status: 'failed',
      errorDetails: error.message,
      retryCount: 1,
    });
    await log.save(); // Save notification log with failure status
  }
}

module.exports = { startSchedulingEngine };
